  wire [4:0] enqOffset_15 = {4'h0, io_in_bits_valid[0]} + {4'h0, io_in_bits_valid[1]} + {4'h0, io_in_bits_valid[2]} + {4'h0, io_in_bits_valid[3]} + {4'h0, io_in_bits_valid[4]} + {4'h0, io_in_bits_valid[5]} + {4'h0, io_in_bits_valid[6]} + {4'h0, io_in_bits_valid[7]} + {4'h0, io_in_bits_valid[8]} + {4'h0, io_in_bits_valid[9]} + {4'h0, io_in_bits_valid[10]} + {4'h0, io_in_bits_valid[11]} + {4'h0, io_in_bits_valid[12]} + {4'h0, io_in_bits_valid[13]} + {4'h0, io_in_bits_valid[14]};

  // ================= 计数与指针运算 =========================================
  wire [4:0] numFromFetch = io_in_valid ? ({4'h0, io_in_bits_enqEnable[0]} + {4'h0, io_in_bits_enqEnable[1]} + {4'h0, io_in_bits_enqEnable[2]} + {4'h0, io_in_bits_enqEnable[3]} + {4'h0, io_in_bits_enqEnable[4]} + {4'h0, io_in_bits_enqEnable[5]} + {4'h0, io_in_bits_enqEnable[6]} + {4'h0, io_in_bits_enqEnable[7]} + {4'h0, io_in_bits_enqEnable[8]} + {4'h0, io_in_bits_enqEnable[9]} + {4'h0, io_in_bits_enqEnable[10]} + {4'h0, io_in_bits_enqEnable[11]} + {4'h0, io_in_bits_enqEnable[12]} + {4'h0, io_in_bits_enqEnable[13]} + {4'h0, io_in_bits_enqEnable[14]} + {4'h0, io_in_bits_enqEnable[15]}) : 5'h0;
