      topdown_stage_reasons_6 <= (ctrlRedir & ~(io_ControlBTBMissBubble | io_TAGEMissBubble | io_SCMissBubble | io_ITTAGEMissBubble) & io_RASMissBubble) | io_in_bits_topdown_info_reasons_6;
      topdown_stage_reasons_7 <= (io_flush & ~io_ControlRedirect & io_MemVioRedirect) | io_in_bits_topdown_info_reasons_7;
      topdown_stage_reasons_8 <= (io_flush & ~(io_ControlRedirect | io_MemVioRedirect)) | io_in_bits_topdown_info_reasons_8;
      topdown_stage_reasons_9 <= io_in_bits_topdown_info_reasons_9;
      topdown_stage_reasons_10 <= io_in_bits_topdown_info_reasons_10;
      topdown_stage_reasons_11 <= io_in_bits_topdown_info_reasons_11;
      topdown_stage_reasons_12 <= (io_flush & io_ControlRedirect & io_ControlBTBMissBubble) | io_in_bits_topdown_info_reasons_12;
      topdown_stage_reasons_13 <= io_in_bits_topdown_info_reasons_13;
      topdown_stage_reasons_14 <= io_in_bits_topdown_info_reasons_14;
      topdown_stage_reasons_15 <= io_in_bits_topdown_info_reasons_15;
      topdown_stage_reasons_16 <= io_in_bits_topdown_info_reasons_16;
