      topdown_stage_reasons_18 <= io_in_bits_topdown_info_reasons_18;
      topdown_stage_reasons_19 <= io_in_bits_topdown_info_reasons_19;
      topdown_stage_reasons_20 <= io_in_bits_topdown_info_reasons_20;
      topdown_stage_reasons_21 <= io_in_bits_topdown_info_reasons_21;
      topdown_stage_reasons_22 <= io_in_bits_topdown_info_reasons_22;
      topdown_stage_reasons_23 <= io_in_bits_topdown_info_reasons_23;
      topdown_stage_reasons_24 <= io_in_bits_topdown_info_reasons_24;
      topdown_stage_reasons_25 <= io_in_bits_topdown_info_reasons_25;
      topdown_stage_reasons_26 <= io_in_bits_topdown_info_reasons_26;
      topdown_stage_reasons_27 <= io_in_bits_topdown_info_reasons_27;
      topdown_stage_reasons_28 <= io_in_bits_topdown_info_reasons_28;
      topdown_stage_reasons_29 <= io_in_bits_topdown_info_reasons_29;
      topdown_stage_reasons_30 <= io_in_bits_topdown_info_reasons_30;
      topdown_stage_reasons_31 <= io_in_bits_topdown_info_reasons_31;
      topdown_stage_reasons_32 <= io_in_bits_topdown_info_reasons_32;
      topdown_stage_reasons_33 <= io_in_bits_topdown_info_reasons_33;
      topdown_stage_reasons_34 <= io_in_bits_topdown_info_reasons_34;
      topdown_stage_reasons_35 <= io_in_bits_topdown_info_reasons_35;
      topdown_stage_reasons_36 <= io_in_bits_topdown_info_reasons_36;
      topdown_stage_reasons_37 <= io_in_bits_topdown_info_reasons_37;
      afterInit <= enqFire | afterInit;
      headBubble <= io_flush | (~(|numValid) & headBubble);
    end
  end

  // 性能事件采样寄存器 (无复位, 对应 golden 的 RegNext 性能链)
  always_ff @(posedge clock) begin
    io_perf_0_value_REG <= io_flush;
    io_perf_1_value_REG <= afterInit & ~(|numValid) & ~headBubble;
    io_perf_2_value_REG <= (|numValid) & (numValid < 6'hC);
    io_perf_3_value_REG <= (numValid > 6'hB) & (numValid < 6'h18);
    io_perf_4_value_REG <= (numValid > 6'h17) & (numValid < 6'h24);
    io_perf_5_value_REG <= (numValid > 6'h23) & (numValid[5:4] != 2'h3);
    io_perf_6_value_REG <= &numValid;
    io_perf_7_value_REG <= io_decodeCanAccept & ~headBubble ? 3'(3'h6 - numOut) : 3'h0;
    io_perf_8_value_REG <= io_decodeCanAccept & ~headBubble & (numOut == 3'h0);
    io_perf_0_value_REG_1 <= io_perf_0_value_REG;
    io_perf_1_value_REG_1 <= io_perf_1_value_REG;
    io_perf_2_value_REG_1 <= io_perf_2_value_REG;
    io_perf_3_value_REG_1 <= io_perf_3_value_REG;
    io_perf_4_value_REG_1 <= io_perf_4_value_REG;
    io_perf_5_value_REG_1 <= io_perf_5_value_REG;
    io_perf_6_value_REG_1 <= io_perf_6_value_REG;
    io_perf_7_value_REG_1 <= io_perf_7_value_REG;
    io_perf_8_value_REG_1 <= io_perf_8_value_REG;
  end

  // ================= 输出端口 (outputEntries -> CtrlFlow) ===================
  assign io_in_ready = allowEnq;

  assign io_out_0_valid = outputEntries_0_valid;
  assign io_out_0_bits_instr = outputEntries_0_bits_inst;
  assign io_out_0_bits_pc = outputEntries_0_bits_pc;
  assign io_out_0_bits_foldpc = outputEntries_0_bits_foldpc;
  assign io_out_0_bits_exceptionVec_1 = &(outputEntries_0_bits_exceptionType[1:0]);
  assign io_out_0_bits_exceptionVec_2 = outputEntries_0_bits_exceptionType[2] & (outputEntries_0_bits_exceptionType[1:0] == 2'h0);
  assign io_out_0_bits_exceptionVec_12 = outputEntries_0_bits_exceptionType[1:0] == 2'h1;
  assign io_out_0_bits_exceptionVec_20 = outputEntries_0_bits_exceptionType[1:0] == 2'h2;
  assign io_out_0_bits_backendException = outputEntries_0_bits_backendException;
  assign io_out_0_bits_trigger = outputEntries_0_bits_triggered;
  assign io_out_0_bits_pd_isRVC = outputEntries_0_bits_pd_isRVC;
  assign io_out_0_bits_pd_brType = outputEntries_0_bits_pd_brType;
  assign io_out_0_bits_pred_taken = outputEntries_0_bits_pred_taken;
  assign io_out_0_bits_crossPageIPFFix = outputEntries_0_bits_exceptionType[2] & (|outputEntries_0_bits_exceptionType[1:0]);
  assign io_out_0_bits_ftqPtr_flag = outputEntries_0_bits_ftqPtr_flag;
  assign io_out_0_bits_ftqPtr_value = outputEntries_0_bits_ftqPtr_value;
  assign io_out_0_bits_ftqOffset = outputEntries_0_bits_ftqOffset;
  assign io_out_0_bits_isLastInFtqEntry = outputEntries_0_bits_isLastInFtqEntry;
  assign io_out_1_valid = outputEntries_1_valid;
  assign io_out_1_bits_instr = outputEntries_1_bits_inst;
  assign io_out_1_bits_pc = outputEntries_1_bits_pc;
  assign io_out_1_bits_foldpc = outputEntries_1_bits_foldpc;
  assign io_out_1_bits_exceptionVec_1 = &(outputEntries_1_bits_exceptionType[1:0]);
  assign io_out_1_bits_exceptionVec_2 = outputEntries_1_bits_exceptionType[2] & (outputEntries_1_bits_exceptionType[1:0] == 2'h0);
  assign io_out_1_bits_exceptionVec_12 = outputEntries_1_bits_exceptionType[1:0] == 2'h1;
  assign io_out_1_bits_exceptionVec_20 = outputEntries_1_bits_exceptionType[1:0] == 2'h2;
  assign io_out_1_bits_backendException = outputEntries_1_bits_backendException;
  assign io_out_1_bits_trigger = outputEntries_1_bits_triggered;
  assign io_out_1_bits_pd_isRVC = outputEntries_1_bits_pd_isRVC;
  assign io_out_1_bits_pd_brType = outputEntries_1_bits_pd_brType;
  assign io_out_1_bits_pred_taken = outputEntries_1_bits_pred_taken;
  assign io_out_1_bits_crossPageIPFFix = outputEntries_1_bits_exceptionType[2] & (|outputEntries_1_bits_exceptionType[1:0]);
  assign io_out_1_bits_ftqPtr_flag = outputEntries_1_bits_ftqPtr_flag;
  assign io_out_1_bits_ftqPtr_value = outputEntries_1_bits_ftqPtr_value;
  assign io_out_1_bits_ftqOffset = outputEntries_1_bits_ftqOffset;
  assign io_out_1_bits_isLastInFtqEntry = outputEntries_1_bits_isLastInFtqEntry;
  assign io_out_2_valid = outputEntries_2_valid;
  assign io_out_2_bits_instr = outputEntries_2_bits_inst;
  assign io_out_2_bits_pc = outputEntries_2_bits_pc;
  assign io_out_2_bits_foldpc = outputEntries_2_bits_foldpc;
  assign io_out_2_bits_exceptionVec_1 = &(outputEntries_2_bits_exceptionType[1:0]);
  assign io_out_2_bits_exceptionVec_2 = outputEntries_2_bits_exceptionType[2] & (outputEntries_2_bits_exceptionType[1:0] == 2'h0);
  assign io_out_2_bits_exceptionVec_12 = outputEntries_2_bits_exceptionType[1:0] == 2'h1;
  assign io_out_2_bits_exceptionVec_20 = outputEntries_2_bits_exceptionType[1:0] == 2'h2;
  assign io_out_2_bits_backendException = outputEntries_2_bits_backendException;
  assign io_out_2_bits_trigger = outputEntries_2_bits_triggered;
  assign io_out_2_bits_pd_isRVC = outputEntries_2_bits_pd_isRVC;
  assign io_out_2_bits_pd_brType = outputEntries_2_bits_pd_brType;
  assign io_out_2_bits_pred_taken = outputEntries_2_bits_pred_taken;
  assign io_out_2_bits_crossPageIPFFix = outputEntries_2_bits_exceptionType[2] & (|outputEntries_2_bits_exceptionType[1:0]);
  assign io_out_2_bits_ftqPtr_flag = outputEntries_2_bits_ftqPtr_flag;
  assign io_out_2_bits_ftqPtr_value = outputEntries_2_bits_ftqPtr_value;
  assign io_out_2_bits_ftqOffset = outputEntries_2_bits_ftqOffset;
  assign io_out_2_bits_isLastInFtqEntry = outputEntries_2_bits_isLastInFtqEntry;
  assign io_out_3_valid = outputEntries_3_valid;
  assign io_out_3_bits_instr = outputEntries_3_bits_inst;
  assign io_out_3_bits_pc = outputEntries_3_bits_pc;
  assign io_out_3_bits_foldpc = outputEntries_3_bits_foldpc;
  assign io_out_3_bits_exceptionVec_1 = &(outputEntries_3_bits_exceptionType[1:0]);
