  assign io_out_4_bits_exceptionVec_2 = outputEntries_4_bits_exceptionType[2] & (outputEntries_4_bits_exceptionType[1:0] == 2'h0);
  assign io_out_4_bits_exceptionVec_12 = outputEntries_4_bits_exceptionType[1:0] == 2'h1;
  assign io_out_4_bits_exceptionVec_20 = outputEntries_4_bits_exceptionType[1:0] == 2'h2;
  assign io_out_4_bits_backendException = outputEntries_4_bits_backendException;
  assign io_out_4_bits_trigger = outputEntries_4_bits_triggered;
  assign io_out_4_bits_pd_isRVC = outputEntries_4_bits_pd_isRVC;
  assign io_out_4_bits_pd_brType = outputEntries_4_bits_pd_brType;
  assign io_out_4_bits_pred_taken = outputEntries_4_bits_pred_taken;
  assign io_out_4_bits_crossPageIPFFix = outputEntries_4_bits_exceptionType[2] & (|outputEntries_4_bits_exceptionType[1:0]);
  assign io_out_4_bits_ftqPtr_flag = outputEntries_4_bits_ftqPtr_flag;
  assign io_out_4_bits_ftqPtr_value = outputEntries_4_bits_ftqPtr_value;
  assign io_out_4_bits_ftqOffset = outputEntries_4_bits_ftqOffset;
  assign io_out_4_bits_isLastInFtqEntry = outputEntries_4_bits_isLastInFtqEntry;
  assign io_out_5_valid = outputEntries_5_valid;
  assign io_out_5_bits_instr = outputEntries_5_bits_inst;
  assign io_out_5_bits_pc = outputEntries_5_bits_pc;
  assign io_out_5_bits_foldpc = outputEntries_5_bits_foldpc;
  assign io_out_5_bits_exceptionVec_1 = &(outputEntries_5_bits_exceptionType[1:0]);
  assign io_out_5_bits_exceptionVec_2 = outputEntries_5_bits_exceptionType[2] & (outputEntries_5_bits_exceptionType[1:0] == 2'h0);
  assign io_out_5_bits_exceptionVec_12 = outputEntries_5_bits_exceptionType[1:0] == 2'h1;
  assign io_out_5_bits_exceptionVec_20 = outputEntries_5_bits_exceptionType[1:0] == 2'h2;
  assign io_out_5_bits_backendException = outputEntries_5_bits_backendException;
  assign io_out_5_bits_trigger = outputEntries_5_bits_triggered;
  assign io_out_5_bits_pd_isRVC = outputEntries_5_bits_pd_isRVC;
  assign io_out_5_bits_pd_brType = outputEntries_5_bits_pd_brType;
  assign io_out_5_bits_pred_taken = outputEntries_5_bits_pred_taken;
  assign io_out_5_bits_crossPageIPFFix = outputEntries_5_bits_exceptionType[2] & (|outputEntries_5_bits_exceptionType[1:0]);
  assign io_out_5_bits_ftqPtr_flag = outputEntries_5_bits_ftqPtr_flag;
  assign io_out_5_bits_ftqPtr_value = outputEntries_5_bits_ftqPtr_value;
  assign io_out_5_bits_ftqOffset = outputEntries_5_bits_ftqOffset;
  assign io_out_5_bits_isLastInFtqEntry = outputEntries_5_bits_isLastInFtqEntry;

  // stallReason: backReason 优先, 否则按浪费的出队槽数填 stallVal
  assign io_stallReason_reason_0 = io_stallReason_backReason_valid
    ? io_stallReason_backReason_bits : ((deqWasteCount > 3'h5) ? stallVal : 6'h0);
  assign io_stallReason_reason_1 = io_stallReason_backReason_valid
    ? io_stallReason_backReason_bits : ((deqWasteCount > 3'h4) ? stallVal : 6'h0);
  assign io_stallReason_reason_2 = io_stallReason_backReason_valid
    ? io_stallReason_backReason_bits : ((deqWasteCount[2]) ? stallVal : 6'h0);
  assign io_stallReason_reason_3 = io_stallReason_backReason_valid
    ? io_stallReason_backReason_bits : ((deqWasteCount > 3'h2) ? stallVal : 6'h0);
  assign io_stallReason_reason_4 = io_stallReason_backReason_valid
    ? io_stallReason_backReason_bits : ((|deqWasteCount[2:1]) ? stallVal : 6'h0);
  assign io_stallReason_reason_5 = io_stallReason_backReason_valid
    ? io_stallReason_backReason_bits : ((|deqWasteCount) ? stallVal : 6'h0);

  assign io_perf_0_value = {5'h0, io_perf_0_value_REG_1};
  assign io_perf_1_value = {5'h0, io_perf_1_value_REG_1};
  assign io_perf_2_value = {5'h0, io_perf_2_value_REG_1};
  assign io_perf_3_value = {5'h0, io_perf_3_value_REG_1};
  assign io_perf_4_value = {5'h0, io_perf_4_value_REG_1};
  assign io_perf_5_value = {5'h0, io_perf_5_value_REG_1};
  assign io_perf_6_value = {5'h0, io_perf_6_value_REG_1};
  assign io_perf_7_value = {3'h0, io_perf_7_value_REG_1};
  assign io_perf_8_value = {5'h0, io_perf_8_value_REG_1};

endmodule
